// Registro de usuario — v2.0 (refactorizado)
// Números mágicos → constantes con nombre.
// Una función = una responsabilidad.

const NOMBRE_MIN = 3;
const EDAD_MIN = 18;
const EDAD_JOVEN = 25;
const EDAD_SENIOR = 60;
const DESC_JOVEN = 10;
const DESC_SENIOR = 20;

function validar(nombre, email, edad) {
  if (nombre.length < NOMBRE_MIN) return { ok: false, error: 'Nombre muy corto' };
  if (!email.includes('@')) return { ok: false, error: 'Email invalido' };
  if (edad < EDAD_MIN) return { ok: false, error: 'Debe ser mayor de edad' };
  return null;
}

function calcularDescuento(edad) {
  if (edad < EDAD_JOVEN) return DESC_JOVEN;
  if (edad >= EDAD_SENIOR) return DESC_SENIOR;
  return 0;
}

function categorizar(edad) {
  if (edad < EDAD_JOVEN) return 'joven';
  if (edad >= EDAD_SENIOR) return 'senior';
  return 'normal';
}

function registrarUsuario(nombre, email, edad) {
  const error = validar(nombre, email, edad);
  if (error) return error;
  const categoria = categorizar(edad);
  const descuento = calcularDescuento(edad);
  console.log(`Usuario: ${nombre} | Email: ${email} | Cat: ${categoria}`);
  return { ok: true, nombre, email, categoria, descuento };
}

